Identify the bug in the following recursive binary search implementation and write the corrected Python version:

def binary_search(arr, low, high, x):
    if high >= low:
        mid = (high + low) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] > x:
            return binary_search(arr, low, mid, x)
        else:
            return binary_search(arr, mid, high, x)
    return -1
